// CHECK DUE TASKS FROM SUPABASE
// ✅ v5: joins users table to get phone_number explicitly
// ══════════════════════════════════════════
const url = $env.SUPABASE_URL;
const key = $env.SUPABASE_KEY;
const now = new Date().toISOString();

if (!url || !key) {
  console.warn('Supabase not configured — using static data fallback');
  const state = $getWorkflowStaticData('global');
  const allTasks = state.tasks || {};
  const dueTasks = [];
  for (const userId in allTasks) {
    for (const task of (allTasks[userId] || [])) {
      if (!task.sent && task.due_at) {
        const dueTime = new Date(task.due_at);
        if (!isNaN(dueTime) && dueTime <= new Date()) {
          dueTasks.push({ ...task, user_id: userId });
        }
      }
    }
  }
  return dueTasks.map(t => ({ json: t }));
}

try {
  // ✅ join users to get phone_number — never parse user_id
  const response = await $http.request({
    method: 'GET',
    url: `${url}/rest/v1/tasks?sent=eq.false&due_at=lte.${now}&select=*,users(phone_number)`,
    headers: {
      'apikey': key,
      'Authorization': `Bearer ${key}`,
      'Content-Type': 'application/json'
    }
  });
  const tasks = JSON.parse(response) || [];
  if (tasks.length === 0) return [];
  // Flatten phone_number from joined users object
  return tasks.map(t => ({
    json: {
      ...t,
      phone_number: t.users?.phone_number || null
    }
  }));
} catch(e) {
  console.error('Failed to fetch due tasks:', e.message);
  return [];
}

