// Mark task as sent in Supabase
// ✅ v5: retry logic added — prevents double-send on Supabase write failure
const d   = $input.first().json;
const url = $env.SUPABASE_URL;
const key = $env.SUPABASE_KEY;

if (!url || !key || !d.id) {
  // Fallback: mark in static data
  const state = $getWorkflowStaticData('global');
  if (state.tasks && state.tasks[d.user_id]) {
    state.tasks[d.user_id] = state.tasks[d.user_id].map(t =>
      t.task === d.task ? { ...t, sent: true } : t
    );
  }
  return [$input.first()];
}

// ✅ Retry up to 3 times before giving up
const MAX_RETRIES = 3;
let lastError;

for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
  try {
    await $http.request({
      method: 'PATCH',
      url: `${url}/rest/v1/tasks?id=eq.${d.id}`,
      headers: {
        'apikey': key,
        'Authorization': `Bearer ${key}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({ sent: true })
    });
    // Success — exit retry loop
    return [$input.first()];
  } catch(e) {
    lastError = e;
    console.warn(`Mark-sent attempt ${attempt} failed: ${e.message}`);
    if (attempt < MAX_RETRIES) {
      await new Promise(r => setTimeout(r, 500 * attempt)); // exponential backoff
    }
  }
}

// All retries failed — log but don't crash the workflow
console.error(`Failed to mark task ${d.id} as sent after ${MAX_RETRIES} attempts: ${lastError?.message}`);
return [$input.first()];

// ══════════════════════════════════════════
// BUILD DAILY SUMMARY REPORT  [NEW - Tier 3]
// ══════════════════════════════════════════
const url = $env.SUPABASE_URL;
const key = $env.SUPABASE_KEY;

const today     = new Date();
today.setHours(0,0,0,0);
const yesterday = new Date(today);
yesterday.setDate(yesterday.getDate() - 1);

let stats = { total: 0, users: 0, tasks: 0, questions: 0, greetings: 0, commands: 0, unknown: 0 };

if (url && key) {
  try {
    const response = await $http.request({
      method: 'GET',
      url: `${url}/rest/v1/conversations?timestamp=gte.${yesterday.toISOString()}&timestamp=lt.${today.toISOString()}&select=intent,user_id`,
      headers: { 'apikey': key, 'Authorization': `Bearer ${key}` }
    });
    const rows = JSON.parse(response) || [];
    stats.total      = rows.length;
    stats.users      = new Set(rows.map(r => r.user_id)).size;
    stats.tasks      = rows.filter(r => r.intent === 'task').length;
    stats.questions  = rows.filter(r => r.intent === 'question').length;
    stats.greetings  = rows.filter(r => r.intent === 'greeting').length;
    stats.commands   = rows.filter(r => r.intent === 'command').length;
    stats.unknown    = rows.filter(r => r.intent === 'unknown').length;
  } catch(e) {
    console.warn('Stats fetch failed:', e.message);
  }
}

const report = `📊 *Daily Report — WhatsApp AI Agent*
📅 ${yesterday.toLocaleDateString('ar-SA')}

💬 Messages: ${stats.total}
👤 Unique users: ${stats.users}

📋 Intents breakdown:
✅ Tasks: ${stats.tasks}
❓ Questions: ${stats.questions}
👋 Greetings: ${stats.greetings}
⚡ Commands: ${stats.commands}
❔ Unknown: ${stats.unknown}

_Sent automatically at 9:00 AM_`;

return [{ json: { report } }];
